Object.assign(dictionaries.zh, { "concept.bazi.intro": "八字也叫四柱命理，会把出生年、月、日、时组合成命盘，用来观察个性结构、阶段起伏与五行之间的动态关系。", "concept.bazi.pillars": "四柱详解", "concept.bazi.pillarsIntro": "八字由四柱组成，每一柱都对应人生里不同的观察层次。", "concept.bazi.year": "代表祖上、早年运势和社会关系，影响他人对你的第一印象。", "concept.bazi.month": "代表父母、事业潜力和性格基础，是命盘里很重要的结构位置。", "concept.bazi.day": "代表自我、性格核心和亲密关系，是整张命盘的观察中心。", "concept.bazi.time": "代表子女、创造力、后期运势和人生逐渐展开的成果。", "concept.bazi.wood": "木代表生长、创造力和仁爱。", "concept.bazi.fire": "火代表热情、活力和变化。", "concept.bazi.earth": "土代表稳定、包容和承载力。", "concept.bazi.metal": "金代表果断、秩序和原则。", "concept.bazi.water": "水代表智慧、流动和沟通。", "concept.bazi.elements": "五行学说", "concept.bazi.elementsIntro": "八字分析也会看木、火、土、金、水之间的相生相克，不同元素的偏强偏弱，往往会影响一个人的表达方式和处事重心。", "concept.ziwei.intro": "紫微斗数会把个人信息映射到十二宫位与星曜组合中，用来观察人生主题、关系结构与阶段变化。", "concept.ziwei.palaces": "围绕命宫、财帛、事业、夫妻等宫位关系，观察人生不同主题的重心分布。", "concept.ziwei.stars": "关注紫微、天府、武曲、廉贞等主星组合，帮助理解个性结构与人生驱动力。", "concept.ziwei.modern": "保留传统斗数结构，同时用更清晰的卡片与文字呈现，降低阅读门槛。", "concept.chenggu.intro": "称骨算命会把出生的农历年、月、日、时换算成对应骨重，用总骨重和歌诀去看一生的总体基调。", "concept.chenggu.weights": "按照农历出生年、月、日、时分别取值，再汇总成总骨重。", "concept.chenggu.light": "相比八字和紫微，称骨更像一种快速读法，适合作为总体气质与人生节奏的概览。", "concept.chenggu.modern": "保留传统歌诀，同时补上拆分明细与更克制的结果表达，方便理解来源。" }); Object.assign(dictionaries.en, { "concept.bazi.intro": "Bazi, also called Four Pillars, combines your birth year, month, day, and hour into a chart for observing character, life phases, and the dynamic balance of the Five Elements.", "concept.bazi.pillars": "The Four Pillars", "concept.bazi.pillarsIntro": "Bazi has four pillars, each offering a different lens on life.", "concept.bazi.year": "Ancestors, early life, and social relationships; it shapes first impressions.", "concept.bazi.month": "Parents, career potential, and personality foundations; a central structural position.", "concept.bazi.day": "Self, core character, and intimate relationships; the center of the chart.", "concept.bazi.time": "Children, creativity, later life, and the results that unfold over time.", "concept.bazi.wood": "Wood represents growth, creativity, and benevolence.", "concept.bazi.fire": "Fire represents passion, vitality, and change.", "concept.bazi.earth": "Earth represents stability, generosity, and support.", "concept.bazi.metal": "Metal represents decisiveness, order, and principle.", "concept.bazi.water": "Water represents wisdom, flow, and communication.", "concept.bazi.elements": "The Five Elements", "concept.bazi.elementsIntro": "Bazi also observes how Wood, Fire, Earth, Metal, and Water support or restrain each other; their balance often shapes expression and priorities.", "concept.ziwei.intro": "Zi Wei Dou Shu maps personal information to twelve palaces and star combinations to observe life themes, relationships, and phases of change.", "concept.ziwei.palaces": "Observe how palaces such as life, wealth, career, and partnership distribute attention across life themes.", "concept.ziwei.stars": "Focus on combinations of major stars to understand character structure and motivation.", "concept.ziwei.modern": "Keep the traditional structure while presenting it through clearer cards and language.", "concept.chenggu.intro": "Weight-of-bones divination converts the lunar birth year, month, day, and hour into weights and reads the overall tone through the total and its verse.", "concept.chenggu.weights": "Take a value from the lunar birth year, month, day, and hour, then add them into a total weight.", "concept.chenggu.light": "Compared with Bazi and Zi Wei, this is a quicker reading for an overview of temperament and life rhythm.", "concept.chenggu.modern": "Keep the traditional verse while adding a clearer breakdown and restrained result language." });
Object.assign(dictionaries.zh, { "concept.liuyao.intro": "六爻占卜会围绕一个明确问题起卦，通过六条爻位、本卦、动爻和变卦，观察事情的当下结构与变化方向。", "concept.liuyao.problem": "六爻更适合处理当下正在发生的现实问题，比如关系推进、合作得失、是否行动。", "concept.liuyao.change": "本卦偏向当前格局，动爻提示关键变化点，变卦则更像局势后续可能展开的方向。", "concept.liuyao.basic": "当前版本先提供起卦、本卦、变卦与动爻结果，后续再继续补齐世应、六亲等专业层。", "concept.meihua.intro": "梅花易数偏重“触机而占”，通过象、数与时间建立卦象，再从本卦、互卦、变卦和体用关系中观察事情的状态与趋势。", "concept.meihua.image": "梅花易数重在从时间、数字、外应等线索入卦，适合围绕当下具体事项快速判断变化方向。", "concept.meihua.layers": "本卦看当前格局，互卦看内在过程，变卦看后续转折，动爻用于定位关键变化点。", "concept.meihua.body": "系统会根据动爻区分体卦与用卦，并给出五行生克关系，作为后续 AI 解读的结构化依据。" }); Object.assign(dictionaries.en, { "concept.liuyao.intro": "Six Yao begins with a clear question and uses six lines, the primary hexagram, moving lines, and the changed hexagram to observe the present structure and direction of change.", "concept.liuyao.problem": "Six Yao works well for concrete situations unfolding now, such as relationships, partnerships, or whether to act.", "concept.liuyao.change": "The primary hexagram reflects the current pattern, moving lines point to change, and the changed hexagram suggests what may unfold next.", "concept.liuyao.basic": "This version provides the cast, primary and changed hexagrams, and moving lines; more traditional fields will follow.", "concept.meihua.intro": "Meihua Yishu builds a hexagram from images, numbers, and time, then reads the present state and trend through primary, mutual, changed, and body/use relationships.", "concept.meihua.image": "Use time, numbers, and external signs to form a hexagram and quickly assess the direction of a current situation.", "concept.meihua.layers": "The primary hexagram shows the current pattern, the mutual hexagram the inner process, and the changed hexagram the next turn.", "concept.meihua.body": "The system separates body and use based on the moving line and provides a structured Five Element relationship for AI interpretation." });
