export function isLocale(value: string | undefined): value is Locale {
  return Boolean(value && locales.includes(value as Locale));
}

export function localeFromLanguage(language: string | undefined): Locale {
  const normalized = language?.split(",")[0]?.split("-")[0];
  return isLocale(normalized) ? normalized : defaultLocale;
}

export function getDictionary(locale: Locale = defaultLocale) {
  return dictionaries[locale];
}

export function translate(locale: Locale, key: string, values?: Record<string, string | number>) {
  let value = getDictionary(locale)[key] ?? getDictionary(defaultLocale)[key] ?? key;
  for (const [name, replacement] of Object.entries(values ?? {})) {
    value = value.replaceAll(`{${name}}`, String(replacement));
  }
  return value;
}
